var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"좌표 입력 확인, 위성 포격 시스템 '굿나잇 키스' 가동.","JPN":"座標入力確認、衛星砲撃システム「グッドナイト・キス」稼働。","ENG":"Checking the entered coordinates... Activating the satellite cannonade system, Good Night Kiss...","TWN":"確認輸入座標，啟動衛星炮擊系統“晚安之吻”。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH"},{"id":"L5_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"하하하하! 아하하하핫!! 내 단잠을 깨운 것들을 모두 태워 버려!","JPN":"ハハハ！　アハハハッ！　私の睡眠の邪魔をしたやつらを燃やし尽くしちまえ～！","ENG":"Hah hah hah! Mwa hah hah hah! Let them burn! They disturbed my sleep!","TWN":"哈哈哈哈！啊哈哈哈！！打擾我睡覺的人通通燒毀吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BOOM_REPEAT"},{"id":"L6_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"이, 이런! 이대론 전멸이야!","JPN":"まずい！　このままでは全滅だ！","ENG":"Oh, no. She's going to wipe us out!","TWN":"該、該死！這樣下去會全滅的！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"다들, 일단 물러선다! 후퇴!","JPN":"一旦撤退だ！　全員撤退しろ！","ENG":"Everyone, go back! Retreat!","TWN":"所有人暫時撤退！撤退！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"적들이 후퇴하고 있네요. 이번에도 저의 멋진 승리인 걸로?","JPN":"敵が撤退したようですね。今回も僕たちの見事な勝利ということですかね？","ENG":"They're retreating. It's my victory again!","TWN":"敵人正在撤退呢，看來這次又是我們的勝利吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그게 문제가 아니라고 이 여자야!","JPN":"そんなこと言ってる場合ですか！","ENG":"Hey, that's not the problem!","TWN":"問題不在這裡吧，妳這女人！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이대로 가다간 학교 건물까지 전부 무너지게 생겼잖아!","JPN":"このままじゃ、学校が焼け野原になっちゃいます！","ENG":"At this rate, even the school buildings are going to get destroyed!","TWN":"妳沒看到再這樣下去，整個學校大樓都要倒塌了嗎！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그건 걱정 마세요. 이럴 때를 위해서 제가 옆에 붙어 있는 거니까요.","JPN":"それは心配ありません。こういう時のために私が傍についているのです。","ENG":"Don't worry. This is why I'm with her.","TWN":"不用擔心，我就是為了應付這種時候才會待在她旁邊的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"크하하핫......!","JPN":"アハハハッ……！","ENG":"Bwa hah hah hah—","TWN":"哇哈哈哈……！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"에극?!","JPN":"うっ！","ENG":"Ack?","TWN":"呃？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOOM_REPEAT"},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"......쿠울......","JPN":"……すやぁ……","ENG":"Zzz...","TWN":"……呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"우와, 손가락 하나로 사람을 기절시켰어......","JPN":"うわぁ、指一本で気絶させた……","ENG":"Whoa, you knocked her out with just a finger!","TWN":"哇，只用一根手指就把人點暈了……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"무협지에서나 나오는 기술인 줄 알았는데, 저런 게 실제로 가능한 줄은 몰랐네요.","JPN":"小説や漫画に出てくる技だとばかり思ってましたけど、あんなものが実在するなんて知りませんでした。","ENG":"I thought that was only possible in Chinese fantasy novels.","TWN":"我還以為這招只能武俠小說中看到，沒想到現實中也存在啊。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그거, 수류탄을 반으로 갈라서 불발시킨 사람 입에서 나올 법한 대사는 아니지 않아요?","JPN":"それ、手榴弾を真っ二つに切り裂いて不発にした人が言う台詞ではないですよね？","ENG":"That doesn't sound right, coming from someone who can disarm grenades by cutting them in half.","TWN":"呃，這應該不是能將手榴彈一刀兩斷的人該說的台詞吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"상황이 진정된 듯 하니 정식으로 감사 인사를 드려야겠네요.","JPN":"落ち着いたようですので、ちゃんとお礼を言わせていただきましょう。","ENG":"Now that the situation is settled, let me thank you in a more formal capacity.","TWN":"看來情況穩定下來了，我在這裡向大家正式地致謝。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스를 지킬 수 있었던 건 여러분들 덕분이에요. 신세를 졌어요.","JPN":"イーディスを守れたのは、皆さんのおかげです。ありがとうございました。","ENG":"It was because of you I could protect Edith. I'm forever indebted to you.","TWN":"我之所以能守住伊蒂絲，全多虧了大家的幫忙，非常謝謝你們。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아닙니다. 딱히 저희가 활약할 겨를도 없었는걸요.","JPN":"いえ、特に私たちが手を出す暇もなく終わってしまいましたので。","ENG":"Not at all. We didn't do much.","TWN":"哪裡，我們幾乎沒什麼表現空間啊。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"귀하와 동료 분의 실력을 봤을 때 저희가 없었어도 별 일은 없었을 겁니다.","JPN":"あなた方なら、私たちがいなくても何ら問題はなかったでしょう。","ENG":"You and your friend are so strong, you would have been just fine without us.","TWN":"看到你們兩個人的實力，就算沒有我們也沒問題吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"아기펭귄...... 귀여워...... 으음......","JPN":"ペンギンの赤ちゃん……カワイイ……う～ん……","ENG":"Baby penguins... So cute... *Smacks her lips*","TWN":"小企鵝……可愛……唔……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"과찬의 말씀이세요.","JPN":"身に余る言葉です。","ENG":"I'm flattered.","TWN":"過獎了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그나저나 감사하다는 말만으로는 곤란하겠죠.","JPN":"しかし、お礼を言うだけで済ませるわけにはいきません。","ENG":"But just saying thank you isn't enough.","TWN":"但光是用說的不足以表達我的感謝。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"은혜는 반드시 갚는 것이 저희 학생회의 원칙. 제가 여러분을 도와드려도 될까요?","JPN":"私たち生徒会の原則は、借りた恩は必ず返すこと。\\n私に皆さんのお手伝いをさせていただいてもよろしいでしょうか？","ENG":"The Student Council never forgets favors done for its members. Mind if I help you?","TWN":"有恩必報是學生會的一貫原則，能否讓我幫助各位呢？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"네? 저희를 돕는다고요?","JPN":"はい？ 手伝う？","ENG":"Sorry? You want to help us?","TWN":"咦？幫助我們？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"네, 여러분은 운명의 상대를 찾아 이 곳에 오셨다고 하셨죠.","JPN":"はい、皆さんは運命の相手を探しにいらしたのですよね？","ENG":"Yes. You said you came here looking for a soul mate.","TWN":"是的，各位說是為了尋找命運之人來到這裡的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아쉽게도 이 학교에는 딱히 운명의 상대랄 만한 사람이 없는 것 같지만......","JPN":"残念ながら、この学校に運命の相手と言えるような人はいなさそうですが……","ENG":"I don't think you will find him in this school,","TWN":"很遺憾的，在這間學校裡，似乎沒有人可以成為妳的命運之人……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"어쩌면 여러분과 저희 사이에 얽힌 인연 또한 운명의 고리일지도 모르겠네요.","JPN":"もしかしたら皆さんと私たちの間に結ばれた縁も、運命の輪なのかもしれません。","ENG":"but I believe it's an act of providence that we met.","TWN":"但或許，這代表各位和我們之間纏繞的緣分，也是命運之輪的一環。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그러니 여러분들을 블루로즈 섬으로 초대하고 싶군요.","JPN":"そのため皆さんを、ブルーローズ島に招待させていただきたいのです。","ENG":"I'd like to invite you over to Blue Rose Island.","TWN":"所以我想邀請各位去藍玫瑰島。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그곳이라면 운명적인 상대를 만나기에 가장 적합한 곳이라고 생각하는데요.","JPN":"そこでなら運命的な相手を見つけるのにピッタリかと思いまして。","ENG":"If there's a place for fateful love, that has to be it.","TWN":"要遇到命運之人，我覺得那裡是最佳場所。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"브, 블루로즈! 그게 정말인가요?","JPN":"ブ、ブルーローズ！　それって本当ですか？","ENG":"B-Blue Rose! Are you serious?","TWN":"藍、藍玫瑰！這是真的嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"음? 그게 어딘데요? 유명한 곳인가요?","JPN":"うん？　それってどこですか？　有名な場所？","ENG":"Mm? Where is it? Is it famous?","TWN":"嗯？那是什麼地方？很有名嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"블루로즈는 전 세계에서 가장 유명한 관광지 중의 하나라고요!","JPN":"ブルーローズは世界で最も有名な観光地の一つですよ！","ENG":"Blue Rose is one of the world's most famous tourist sites!","TWN":"藍玫瑰是全世界最著名的觀光景點之一！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"특히 이맘때 벌어지는 불꽃놀이 축제는 연인들의 성지로 유명하죠!","JPN":"しかも！　この時期に開催される花火大会は、恋人たちの聖地で有名なんです！","ENG":"Its annual fireworks festival, which takes place around this time, is famous among lovers in bloom!","TWN":"尤其是這個時期舉行的煙火慶典，更是以戀人的聖地而聞名！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아하, 그렇군요! 로맨틱한 장소들에 대해 잘 아시나 봐요?","JPN":"へぇ！　ロマンチックな場所について詳しいんですね？","ENG":"Aha, I see! You know so many romantic places, huh?","TWN":"啊哈，原來如此！看來妳對浪漫的場所很熟悉喔？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아 그건, 제 운명의 상대와 함께 가보게 될 데이트 코스를 여기저기 찾아보다가......","JPN":"それは、私の運命の相手と一緒に行くデートコースを探してて……","ENG":"Oh, this is because I've been looking for places to visit with my soul mate—","TWN":"啊，那個，是因為我經常會找一些適合和命運之人一起約會的場所……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어, 어쨌든!","JPN":"と、とにかく！","ENG":"A-anyways!","TWN":"總、總之！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"블루로즈 초대권은 엄청 비싼데다가 최소한 일 년 전에는 예약해야 하는 걸로 알고 있습니다만......","JPN":"ブルーローズへの招待券はすごく高いですし、1年以上前から予約しないと取れないって聞きましたよ？","ENG":"It costs a lot just to buy the Blue Rose admission ticket, and I thought you had to make a reservation at least a year ahead.","TWN":"據說藍玫瑰的邀請函不但非常昂貴，而且至少得提前一年預約才行……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그 많은 티켓을 어떻게 구하셨다는 거죠?","JPN":"そんな大量のチケット、どうやって手に入れるんですか？","ENG":"Where would you get so many tickets?","TWN":"妳是從哪裡拿到那麼多入場券的？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"후훗, 티켓 같은 건 필요 없어요.","JPN":"ふふっ、チケットは必要ありません。","ENG":"Hah hah. We don't need tickets.","TWN":"呵呵，我們不需要入場券。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"블루로즈는 저희 아카데미가 소유한 섬이거든요.","JPN":"ブルーローズは、私たちアカデミーが所有している島ですから。","ENG":"Blue Rose belongs to the Academy.","TWN":"藍玫瑰島是我們學院的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"가령 운동회 같은 교내 연례 행사를 그곳에서 진행하곤 하죠.","JPN":"運動会などの校内行事をそこで行ったりしています。","ENG":"We hold field days and other school events there.","TWN":"像是運動會這種校內慣例的活動，都是在那裡舉行的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"우, 운동회......?","JPN":"う、運動会……？","ENG":"F-field days?","TWN":"運、運動會……？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"방학 때는 쓰일 일이 없기 때문에, 주로 관광객을 받고 있긴 하지만......","JPN":"休みの時期は使わないので、観光客を受け入れていますが……","ENG":"Since we don't use it during school breaks, we accept tourists for the time being.","TWN":"因為寒、暑假幾乎沒在使用，所以會開放給觀光客……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"학생회장인 제 허가만 있으면 누구든 방문할 수 있어요.","JPN":"生徒会長の私が許可した人物であれば、誰でも訪問可能です。","ENG":"And anyone can enter the island with approval from me, the Student President.","TWN":"只要有我這個學生會長的許可，任何人都可以進入。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"와아...... 굉장하다......","JPN":"わぁ……すごい……","ENG":"Wow! Awesome!","TWN":"哇……好厲害……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그런데 대체 무슨 학교가 뒷마당도 아니고 섬을 가지고 있죠?!","JPN":"でも、学校が裏庭とかではなく、島を持ってるなんて普通じゃないですよね！？","ENG":"But what kind of school is this? Owning an island is not like owning a backyard.","TWN":"話說回來，到底是什麼樣的學校才會擁有一座島嶼，而不是後操場？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그것도 세계 최고의 휴양지를?","JPN":"それも世界最高のリゾート地を？","ENG":"We're talking about the world's greatest resort!","TWN":"而且還是個世界頂級的度假勝地？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"학생들에게 교육과 휴식을 위한 최고의 환경을 제공하는 것이 아카데미 학생회로서의 의무니까요.","JPN":"学生たちに教育と休息のために最高の環境を提供するのが、アカデミー総生徒会としての義務ですから。","ENG":"It's the Student Council's duty to provide its students with the optimal environment to study and relax.","TWN":"為學生的教育和休閒提供最棒的環境，是我們學院學生會的義務。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아, 배는 오늘 오후에 출항할 예정이에요.","JPN":"あっ、船は今日の午後に出航する予定です。","ENG":"Oh, there's a ship to the island this afternoon.","TWN":"啊，船會在今天下午啟航。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"시간은 괜찮으신가요?","JPN":"お時間は大丈夫ですか？","ENG":"Would you be available for this little trip?","TWN":"各位時間方便嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네...... 네! 물론이죠! 되고 말고요! 꼭 가고 싶습니다, 회장님!","JPN":"はっ……はい！　もちろんです！　なくても作ります！　絶対に行きたいです！","ENG":"Yes, yes! Absolutely! I'll make time if I have to! I'd love to go there, Miss President!","TWN":"是……是！當然！當然方便！我一定會去的，會長！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"오호, 비밀의 섬에서 벌어지는 축제와 그곳에서 만나게 될 이름 모를 운명의 상대라......","JPN":"ふ～ん、秘密の島で開催されるお祭りと、そこで運命の相手と出会えるチャンス……","ENG":"Ooo, a festival on a secret island, on which you may find your soul mate...","TWN":"哦吼，在秘密島嶼舉行的慶典，以及在那裡遇到未知的命運之人……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어쩐지 일이 잘 풀리는 것 같은데요, 의뢰인 선생님?","JPN":"いい感じでミッションがクリアできそうですね？","ENG":"It seems everything's going more smoothly than we thought, doesn't it?","TWN":"事情突然進展得非常順利呢，委託人小姐？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"화려한 불꽃놀이 아래에서 마주하게 될 운명적인 만남......","JPN":"綺麗な花火の下で出会う運命の人……","ENG":"A fateful encounter under the sky decorated with beautiful fireworks...","TWN":"在華麗的煙火下，迎接命運的邂逅……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......꿀꺽.","JPN":"ごくり……","ENG":"*Gulp*","TWN":"……吞口水。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};